import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def get_pkgs(data):
    pkgs = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-2]
        for fw in proj['frameworks']:
            for p in fw['topLevelPackages']:
                pkgs[(name, p['id'])] = p['resolvedVersion']
    return pkgs

b, a = get_pkgs(baseline), get_pkgs(after)
if b == a:
    print('All packages resolve identically to baseline.')
else:
    for k in sorted(set(list(b.keys()) + list(a.keys()))):
        bv, av = b.get(k, 'MISSING'), a.get(k, 'MISSING')
        if bv != av: print(f'CHANGED: {k[0]}/{k[1]}: {bv} -> {av}')
"

